// ModelGatewaySyncSummary aggregates the per-gateway connection states into the
// console's sync banner.
func (r *queryResolver) ModelGatewaySyncSummary(ctx context.Context) (*model.ModelGatewaySyncSummary, error) {
	gws, err := r.Ent.GatewayConnection.Query().All(ctx)
	if err != nil {
		return nil, err
	}
	success, failed := 0, 0
	var lastSyncedAt *time.Time
	for _, g := range gws {
		switch g.Status {
		case gatewayconnection.StatusConnected:
			success++
			t := g.UpdatedAt
			if lastSyncedAt == nil || t.After(*lastSyncedAt) {
				lastSyncedAt = &t
			}
		case gatewayconnection.StatusError:
			failed++
		}
	}
	state := model.ModelGatewaySyncStateNever
	switch {
	case len(gws) == 0:
		state = model.ModelGatewaySyncStateNever
	case failed == 0 && success == len(gws):
		state = model.ModelGatewaySyncStateSynced
	case success == 0 && failed > 0:
		state = model.ModelGatewaySyncStateFailed
	case failed > 0:
		state = model.ModelGatewaySyncStatePartial
	}
	return &model.ModelGatewaySyncSummary{
		State:        state,
		LastSyncedAt: lastSyncedAt,
		SuccessCount: success,
		FailedCount:  failed,
	}, nil
}
